const express = require('express');
const path = require('path');
const https = require('https');
const fs = require('fs');
const os = require('os');
const { execFile } = require('child_process');
const multer = require('multer');
const app = express();
const PORT = process.env.PORT || 3000;

// ── 3 Font bundled (base64 → TTF scritti su disco) ──────────
// Poppins Bold   → sans: selFt 0,1,2,4,7
// Caladea Bold   → serif: selFt 3 (Playfair)
// DejaVu Mono    → mono: selFt 6 (Typewriter/Courier)
const FONTS_B64 = {
  sans:  '',
  serif: '',
  mono:  ''
};

// Font map: selFt index → chiave font
const FONT_MAP = ['sans','sans','sans','serif','sans','sans','mono','sans'];

// Percorsi font in memoria
const FONT_PATHS = {};

// Scrive un font su disco se non esiste o se è stato cancellato
function ensureFont(key) {
  const p = path.join(os.tmpdir(), 'cr_font_' + key + '.ttf');
  if (!FONT_PATHS[key] || !fs.existsSync(p)) {
    fs.writeFileSync(p, Buffer.from(FONTS_B64[key], 'base64'));
    FONT_PATHS[key] = p;
    console.log('Font ' + key + ' scritto:', p);
  }
  return FONT_PATHS[key];
}

// Scrive tutti i font all'avvio
Object.keys(FONTS_B64).forEach(k => ensureFont(k));

const upload = multer({ dest: os.tmpdir(), limits: { fileSize: 100*1024*1024 } });

// Converti #RRGGBB → FFmpeg 0xRRGGBBAA
// pct = % trasparenza (0=opaco, 100=trasparente)
function col(hex, pct) {
  if (!hex || hex.length < 7) hex = '#000000';
  const aa = Math.round((1 - (pct||0)/100) * 255).toString(16).padStart(2,'0').toUpperCase();
  return '0x' + hex.replace('#','').toUpperCase() + aa;
}

// Dimensioni video via ffprobe
function getDims(file, cb) {
  execFile('ffprobe', ['-v','quiet','-print_format','json','-show_streams', file],
    { encoding: 'utf8' }, (err, out) => {
      if (err) return cb(1080, 1920);
      try {
        const v = JSON.parse(out).streams.find(s => s.codec_type === 'video');
        cb(v ? v.width : 1080, v ? v.height : 1920);
      } catch(e) { cb(1080, 1920); }
  });
}

// CORS
app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.sendStatus(200);
  next();
});
app.use(express.static(path.join(__dirname)));
app.get('/', (req, res) => res.sendFile(path.join(__dirname, 'story_subtitler.html')));

// ── Debug endpoint ───────────────────────────────────────────
app.get('/api/debug', (req, res) => {
  const info = {
    node: process.version,
    fonts: {},
    ffmpeg: null
  };
  Object.keys(FONTS_B64).forEach(k => {
    const p = path.join(os.tmpdir(), 'cr_font_' + k + '.ttf');
    info.fonts[k] = { path: p, exists: fs.existsSync(p), size: fs.existsSync(p) ? fs.statSync(p).size : 0 };
  });
  execFile('ffmpeg', ['-version'], { encoding: 'utf8' }, (err, out) => {
    info.ffmpeg = err ? 'ERROR: ' + err.message : out.split('\n')[0];
    res.json(info);
  });
});

// ── Trascrizione Groq Whisper ────────────────────────────────
app.post('/api/transcribe', upload.single('file'), (req, res) => {
  const apiKey = process.env.GROQ_API_KEY || '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';
  if (!req.file) return res.status(400).json({ error: 'No file' });
  try {
    const fileData = fs.readFileSync(req.file.path);
    const b = '----CRB' + Date.now(), fn = req.file.originalname || 'audio.mp4';
    const parts = [];
    const field = (n,v) => parts.push(Buffer.from('--'+b+'\r\nContent-Disposition: form-data; name="'+n+'"\r\n\r\n'+v+'\r\n'));
    field('model','whisper-large-v3'); field('language','it');
    field('response_format','verbose_json'); field('timestamp_granularities[]','word');
    parts.push(
      Buffer.from('--'+b+'\r\nContent-Disposition: form-data; name="file"; filename="'+fn+'"\r\nContent-Type: video/mp4\r\n\r\n'),
      fileData, Buffer.from('\r\n--'+b+'--\r\n')
    );
    const body = Buffer.concat(parts);
    const opts = {
      hostname:'api.groq.com', path:'/openai/v1/audio/transcriptions', method:'POST',
      headers:{ 'Authorization':'Bearer '+apiKey, 'Content-Type':'multipart/form-data; boundary='+b, 'Content-Length':body.length }
    };
    const pr = https.request(opts, r => {
      let d=''; r.on('data',c=>d+=c);
      r.on('end',()=>{ fs.unlink(req.file.path,()=>{}); res.status(r.statusCode).json(JSON.parse(d)); });
    });
    pr.on('error', e => { fs.unlink(req.file.path,()=>{}); res.status(500).json({error:e.message}); });
    pr.write(body); pr.end();
  } catch(e) { fs.unlink(req.file.path,()=>{}); res.status(500).json({error:e.message}); }
});

// ── Burn video con drawtext ──────────────────────────────────
app.post('/api/burn', upload.fields([{name:'video', maxCount:1}]), (req, res) => {
  try {
    const videoFile = req.files && req.files.video && req.files.video[0];
    if (!videoFile) return res.status(400).json({error:'No video uploaded'});

    // Parse impostazioni
    let style = {}, chunks = [];
    try { style = JSON.parse(req.body && req.body.style || '{}'); } catch(e) {}
    try {
      const raw = req.body && req.body.chunks;
      chunks = raw ? JSON.parse(raw) : [];
      if (!Array.isArray(chunks)) chunks = [];
    } catch(e) { chunks = []; }

    console.log('BURN: sid=' + style.sid + ' selFt=' + style.selFt + ' chunks=' + chunks.length + ' anim=' + style.anim);

    // CRITICO: ri-verifica che i file font esistano (potrebbero essere stati cancellati da /tmp)
    const fontKey = FONT_MAP[typeof style.selFt === 'number' ? style.selFt : parseInt(style.selFt)||0] || 'sans';
    const fontPath = ensureFont(fontKey);  // garantisce che il file esista
    ensureFont('sans'); ensureFont('serif'); ensureFont('mono'); // refresh tutti

    const inPath = videoFile.path;
    const ts = Date.now() + '_' + Math.random().toString(36).slice(2);
    const outPath = path.join(os.tmpdir(), 'out_' + ts + '.mp4');
    const tmpFiles = [];

    getDims(inPath, (vw, vh) => {
      try {
        const sx = vw / 270, sy = vh / 480;
        const sid = style.sid || 'classic';
        const FP  = fontPath.replace(/'/g, "\'");

        const fontSize = Math.max(14, Math.round((style.fs  || 18) * sx));
        const outlineW = Math.max(1,  Math.round((style.out ||  2) * sx));
        const tc = style.tc || '#FFFFFF';
        const oc = style.oc || '#000000';
        const bottomMargin = Math.round(80 * sy);
        const filters = [];

        // ── Banner ────────────────────────────────────────────
        if (style.bannerText && style.bannerText.trim()) {
          const bTxt  = style.bannerText.trim().toUpperCase();
          const bPath = path.join(os.tmpdir(), 'banner_'+ts+'.txt');
          fs.writeFileSync(bPath, bTxt, 'utf8'); tmpFiles.push(bPath);

          const bfs  = Math.max(12, Math.round((style.bfs || 24) * sx));
          const bpad = Math.round(14 * sx);
          const btop = Math.round(52 * sy);
          const bbg  = col(style.bbg || '#F5821F', 0);   // 0% trasparente = opaco
          const btc  = style.btc || '#FFFFFF';

          filters.push(
            "drawtext=textfile='" + bPath + "':fontfile='" + FP + "'" +
            ":fontsize=" + bfs + ":fontcolor=" + btc +
            ":box=1:boxcolor=" + bbg + ":boxborderw=" + bpad +
            ":x=(w-text_w)/2:y=" + btop
          );
        }

        // ── Sottotitoli ───────────────────────────────────────
        chunks.forEach((chunk, i) => {
          if (!chunk || !chunk.t || !String(chunk.t).trim()) return;
          const txt   = String(chunk.t).trim();
          const tPath = path.join(os.tmpdir(), 'sub_'+ts+'_'+i+'.txt');
          fs.writeFileSync(tPath, txt, 'utf8'); tmpFiles.push(tPath);

          const s = parseFloat(chunk.s) || 0;
          const e = parseFloat(chunk.e) || 0;
          const enable = "between(t," + s.toFixed(3) + "," + e.toFixed(3) + ")";

          // Keyword: se la riga contiene la keyword usa kwc
          const hasKw = style.kw && txt.toLowerCase().includes(String(style.kw).toLowerCase());
          // Classic usa sempre bianco (come nel preview #FFF hardcoded)
          const fontColor = (sid === 'classic') ? '#FFFFFF' : (hasKw ? (style.kwc || '#F5821F') : tc);

          let f = "drawtext=textfile='" + tPath + "'" +
                  ":enable='" + enable + "'" +
                  ":fontfile='" + FP + "'" +
                  ":fontsize=" + fontSize +
                  ":fontcolor=" + fontColor;

          // Stile sottotitolo
          switch (sid) {
            case 'classic':
              // Sfondo scuro semi-trasparente (70% opaco, come preview rgba(0,0,0,.7))
              f += ':box=1:boxcolor=' + col('#000000', 30) + ':boxborderw=' + Math.round(10*sx);
              break;
            case 'bold':
              // Contorno spesso con colore oc + ombra
              f += ':borderw=' + outlineW + ':bordercolor=' + oc +
                   ':shadowx=' + Math.round(2*sx) + ':shadowy=' + Math.round(2*sy) +
                   ':shadowcolor=' + col(oc, 20);
              break;
            case 'neon':
              // Bordo colorato + ombra sovrapposta per simulare il glow
              f += ':borderw=' + Math.max(outlineW, Math.round(2*sx)) + ':bordercolor=' + oc +
                   ':shadowx=0:shadowy=0:shadowcolor=' + oc;
              break;
            case 'highlight':
              // Box con colore oc, completamente opaco (come preview background=oc)
              f += ':box=1:boxcolor=' + col(oc, 0) + ':boxborderw=' + Math.round(10*sx);
              break;
            case 'minimal':
              // Ombra leggera con colore oc (come preview textShadow usa oc)
              f += ':shadowx=' + Math.round(1*sx) + ':shadowy=' + Math.round(1*sy) +
                   ':shadowcolor=' + col(oc, 30);
              break;
            case 'typewriter':
              // Box scuro (55% opaco, come preview rgba(0,0,0,.55))
              f += ':box=1:boxcolor=' + col('#000000', 45) + ':boxborderw=' + Math.round(10*sx);
              break;
            case 'pulito':
              // Solo contorno se outlineW > 0
              if (outlineW > 0) f += ':borderw=' + outlineW + ':bordercolor=' + oc;
              break;
            default:
              f += ':borderw=' + outlineW + ':bordercolor=' + oc;
          }

          // Fade animazione (se attivata e segmento > 0.3s)
          if (style.anim && (e - s) > 0.3) {
            const si = s.toFixed(3), ei = e.toFixed(3);
            const fadeExpr = "if(lt(t-" + si + ",0.15),(t-" + si + ")/0.15," +
                             "if(lt(" + ei + "-t,0.15),(" + ei + "-t)/0.15,1))";
            f += ":alpha='" + fadeExpr + "'";
          }

          f += ':x=(w-text_w)/2:y=h-' + bottomMargin;
          filters.push(f);
        });

        // ── Watermark ─────────────────────────────────────────
        if (style.wmOn && style.wmText && String(style.wmText).trim()) {
          const wmTxt  = String(style.wmText).trim();
          const wmPath = path.join(os.tmpdir(), 'wm_'+ts+'.txt');
          fs.writeFileSync(wmPath, wmTxt, 'utf8'); tmpFiles.push(wmPath);

          const wfs = Math.max(10, Math.round((style.wmSz || 28) * sx));
          const wc  = style.wmC || '#FFFFFF';
          const pos = style.wmPos || 'br';
          const pad = Math.round(24 * sx);
          const padB = Math.round(80 * sy);
          const wx = (pos==='tr'||pos==='br') ? 'w-text_w-'+pad : String(pad);
          const wy = (pos==='bl'||pos==='br') ? 'h-text_h-'+padB : String(Math.round(60*sy));

          filters.push(
            "drawtext=textfile='" + wmPath + "':fontfile='" + FP + "'" +
            ":fontsize=" + wfs + ":fontcolor=" + wc + "@0.75" +
            ":x=" + wx + ":y=" + wy
          );
        }

        // Componi il filtro finale
        const vf   = filters.length ? filters.join(',') : 'null';
        const args = ['-i', inPath, '-vf', vf, '-c:a', 'copy', '-preset', 'ultrafast', '-loglevel', 'warning', '-y', outPath];

        console.log('FFmpeg ' + vw + 'x' + vh + ' font=' + fontKey + ' filters=' + filters.length);

        const cleanup = () => tmpFiles.forEach(f => { try { fs.unlinkSync(f); } catch(e) {} });

        execFile('ffmpeg', args, { maxBuffer: 500*1024*1024 }, (err, stdout, stderr) => {
          try { fs.unlinkSync(inPath); } catch(e) {}
          if (err) {
            cleanup();
            const msg = (stderr || err.message || '').slice(-500);
            console.error('FFmpeg error:', msg);
            if (!res.headersSent) return res.status(500).json({ error: 'FFmpeg: ' + msg });
            return;
          }
          if (!fs.existsSync(outPath)) {
            cleanup();
            if (!res.headersSent) return res.status(500).json({ error: 'Output non creato' });
            return;
          }
          cleanup();
          res.setHeader('Content-Type', 'video/mp4');
          res.setHeader('Content-Disposition', 'attachment; filename="output.mp4"');
          const stream = fs.createReadStream(outPath);
          stream.pipe(res);
          stream.on('end', () => { try { fs.unlinkSync(outPath); } catch(e) {} });
          stream.on('error', e => { if (!res.headersSent) res.status(500).json({ error: e.message }); });
        });

      } catch(innerErr) {
        console.error('Inner error:', innerErr.message, innerErr.stack);
        try { fs.unlinkSync(inPath); } catch(e) {}
        if (!res.headersSent) res.status(500).json({ error: innerErr.message });
      }
    });
  } catch(outerErr) {
    console.error('Outer error:', outerErr.message);
    if (!res.headersSent) res.status(500).json({ error: outerErr.message });
  }
});

app.listen(PORT, () => console.log('CR Story Subtitler on port ' + PORT));
